const target = { message: "Hello, world!" };

const handler = {
  get(obj, prop) {
    console.log(`Property '${prop}' was accessed.`);
    return obj[prop];
  }
};

const proxy = new Proxy(target, handler);

console.log(proxy.message); // Logs access and then the message

const user = { age: 25 };

const validator = {
  set(obj, prop, value) {
    if (prop === 'age') {
      if (!Number.isInteger(value) || value < 0) {
        throw new TypeError('Age must be a positive integer');
      }
    }
    obj[prop] = value;
    return true; // Indicate success
  }
};

const proxyUser = new Proxy(user, validator);

proxyUser.age = 30;  // Works fine
// proxyUser.age = -5; // Throws error
// proxyUser.age = 'old'; // Throws error

const defaults = {
  name: 'Guest',
  score: 0
};

const withDefaults = new Proxy({}, {
  get(obj, prop) {
    return prop in obj ? obj[prop] : defaults[prop];
  }
});

console.log(withDefaults.name); // 'Guest'
withDefaults.name = 'Alex';
console.log(withDefaults.name); // 'Alex'

// Function hoisting example
sayHello(); // Outputs: Hello!

function sayHello() {
  console.log('Hello!');
}

console.log(number); // Outputs: undefined
var number = 5;
console.log(number); // Outputs: 5

import { Kafka } from 'kafkajs';

const kafka = new Kafka({
  clientId: 'my-app',
  brokers: ['localhost:9092']
});

const producer = kafka.producer();

async function produce() {
  await producer.connect();
  console.log('Producer connected');

  try {
    await producer.send({
      topic: 'test-topic',
      messages: [
        { value: JSON.stringify({ event: 'user_signup', userId: 1, timestamp: Date.now() }) }
      ],
    });
    console.log('Message sent');
  } catch (error) {
    console.error('Error sending message:', error);
  }

  await producer.disconnect();
  console.log('Producer disconnected');
}

produce();

import { Kafka } from 'kafkajs';

const kafka = new Kafka({
  clientId: 'my-app',
  brokers: ['localhost:9092']
});

const consumer = kafka.consumer({ groupId: 'test-group' });

async function consume() {
  await consumer.connect();
  console.log('Consumer connected');

  await consumer.subscribe({ topic: 'test-topic', fromBeginning: true });

  await consumer.run({
    eachMessage: async ({ topic, partition, message }) => {
      if (message.value) {
        const event = JSON.parse(message.value.toString());
        console.log(`Received event:`, event);
      }
    },
  });
}

consume().catch(console.error);

